<template><section class="feedback-manager"><header><div><h2>Phản hồi AI</h2><p>Phản hồi chỉ tạo mẫu chờ duyệt; không tự đưa vào dữ liệu học.</p></div><button @click="load">Làm mới</button></header><p v-if="error" class="error">{{ error }}</p><div v-if="loading" class="empty">Đang tải…</div><div v-else-if="!feedback.length" class="empty">Chưa có phản hồi.</div><article v-for="item in feedback" :key="item.id"><div><b>{{ label(item.type) }}</b><span>{{ item.user?.fullName || 'Hệ thống' }} · {{ date(item.createdAt) }}</span><p v-if="item.reasonCode">{{ item.reasonCode }}</p><small>{{ selectionLabel(item.selectionStatus) }} · mức chỉnh sửa {{ item.editDistance ?? 0 }} · báo giá {{ item.quoteGenerated ? 'có' : 'không' }} · đơn hàng {{ item.orderGenerated ? 'có' : 'không' }}</small></div><div v-for="candidate in item.learningCandidates" :key="candidate.id" class="review"><em>Mẫu học: {{ candidateLabel(candidate.status) }}</em><template v-if="['pending','pending_review'].includes(candidate.status)"><button @click="review(candidate.id,'approved')">Duyệt</button><button class="danger" @click="review(candidate.id,'blocked')">Chặn</button></template></div></article></section></template>
<script setup lang="ts">import { onMounted, ref } from 'vue';import { api } from '@/api/index';type Item={id:string;type:string;selectionStatus:string;reasonCode?:string|null;editDistance?:number|null;quoteGenerated:boolean;orderGenerated:boolean;createdAt:string;user?:{fullName:string}|null;learningCandidates:Array<{id:string;status:string}>};const feedback=ref<Item[]>([]),loading=ref(false),error=ref('');const labels:Record<string,string>={good:'Tốt',incorrect_information:'Sai thông tin',context_mismatch:'Sai ngữ cảnh',missing_emotion:'Thiếu cảm xúc',too_long:'Quá dài',too_short:'Quá ngắn',too_robotic:'Quá máy móc',too_pushy:'Quá thúc ép',policy_violation:'Vi phạm chính sách',edited:'Đã chỉnh sửa'};const label=(value:string)=>labels[value]||value;const selectionLabel=(value:string)=>({selected:'đã dùng',skipped:'đã bỏ qua',edited:'đã chỉnh sửa'} as Record<string,string>)[value]||value;const candidateLabel=(value:string)=>({pending:'chờ xem xét',pending_review:'chờ xem xét',approved:'đã duyệt',blocked:'đã chặn',rejected:'đã từ chối',published:'đã áp dụng'} as Record<string,string>)[value]||value;const date=(value:string)=>new Date(value).toLocaleString('vi-VN');async function load(){loading.value=true;error.value='';try{feedback.value=(await api.get<{feedback:Item[]}>('/ai/feedback/manager')).data.feedback}catch(e:any){error.value=e?.response?.data?.error||'Không thể tải phản hồi'}finally{loading.value=false}}async function review(id:string,decision:'approved'|'blocked'){try{await api.post(`/ai/feedback/learning-candidates/${id}/review`,{decision});await load()}catch(e:any){error.value=e?.response?.data?.error||'Không thể xem xét mẫu học'}}onMounted(load);</script>
<style scoped>.feedback-manager{border:1px solid #dbe4f0;border-radius:12px;background:#fff;margin-bottom:24px}.feedback-manager header{display:flex;justify-content:space-between;gap:12px;padding:15px;border-bottom:1px solid #e2e8f0}.feedback-manager h2{font-size:17px;margin:0}.feedback-manager p,.feedback-manager span,.feedback-manager small{font-size:12px;color:#64748b}.feedback-manager article{display:flex;justify-content:space-between;gap:12px;padding:12px 15px;border-bottom:1px solid #f1f5f9}.feedback-manager article:last-child{border-bottom:0}.feedback-manager article p{margin:4px 0}.review{display:flex;gap:6px;align-items:start;white-space:nowrap}.review em{font-size:11px;color:#92400e}.feedback-manager button{border:1px solid #cbd5e1;border-radius:6px;background:#fff;padding:5px 8px;font-size:11px;cursor:pointer}.feedback-manager .danger{border-color:#fecaca;color:#b91c1c}.empty,.error{padding:14px;font-size:12px}.error{color:#b91c1c}@media(max-width:700px){.feedback-manager article{flex-direction:column}.review{flex-wrap:wrap}}</style>